"""MemberCollection ADT - Manages a collection of library members."""from typing import List, Optionalfrom ..models.member import Memberclass MemberCollection:    """    Abstract Data Type for managing a collection of library members.    The implementation (a dictionary keyed by member_id) is hidden.    """    def __init__(self):        self._members = {}  # member_id -> Member    def add_member(self, member):        """        Add a member to the collection.        Raises:            ValueError: If a member with the same ID already exists.        """        if member.member_id in self._members:            raise ValueError(f"Member with ID '{member.member_id}' already exists")        self._members[member.member_id] = member    def remove_member(self, member_id):        """        Remove a member by ID.        Raises:            KeyError: If member not found.            ValueError: If member has borrowed books or outstanding fines.        """        if member_id not in self._members:            raise KeyError(f"Member with ID '{member_id}' not found")        member = self._members[member_id]        if member.get_borrowed_count() > 0:            raise ValueError("Cannot remove member with borrowed books")        if member.get_fines_owed() > 0:            raise ValueError("Cannot remove member with outstanding fines")        del self._members[member_id]        return member    def find_by_id(self, member_id):        """Find a member by exact ID match."""        return self._members.get(member_id)    def find_by_name(self, name_substring):        """        Find members by name (partial match, case-insensitive).        Returns:            List of matching members.        """        search_term = name_substring.lower()        results = []        for member in self._members.values():            if search_term in member.name.lower():                results.append(member)        return results    def get_all_members(self):        """Return a list of all members (defensive copy)."""        return list(self._members.values())    def get_active_members(self):        """Return a list of active members."""        return [m for m in self._members.values() if m.is_active()]    def get_members_with_fines(self):        """Return a list of members with outstanding fines."""        return [m for m in self._members.values() if m.get_fines_owed() > 0]    def count(self):        """Return the total number of members."""        return len(self._members)